-- MVP-59 1,777-department runtime mapping.
-- This migration defines persistence only. It does not enable command execution, deploy execution, rollback execution, alert sending, or arbitrary activation beyond the approved 1,777-department mapping.
-- full 47,979 activation is blocked. activate_all is blocked. Mapping is not activation.

create extension if not exists pgcrypto;

create table if not exists runtime_kernel_config (
  key text primary key,
  value jsonb not null,
  updated_at timestamptz not null default now()
);

create or replace function runtime_department_touch_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

create table if not exists runtime_departments (
  department_id text primary key,
  department_name text not null,
  family_id text,
  family_name text,
  unit_id text,
  unit_name text,
  registered_agent_count integer not null default 0,
  runtime_status text not null default 'mapped_readonly',
  activation_eligible boolean not null default false,
  command_execution_enabled boolean not null default false,
  deploy_execution_enabled boolean not null default false,
  rollback_execution_enabled boolean not null default false,
  alert_sending_enabled boolean not null default false,
  source text not null default 'mvp59_department_runtime_mapping',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint runtime_departments_status_check check (runtime_status in ('unmapped', 'mapped_readonly', 'readiness_review', 'eligible_for_supervised_runtime', 'blocked', 'disabled'))
);

create trigger runtime_departments_touch_updated_at
before update on runtime_departments
for each row execute function runtime_department_touch_updated_at();

create table if not exists runtime_department_lane_assignments (
  id uuid primary key default gen_random_uuid(),
  department_id text references runtime_departments(department_id) on delete cascade,
  runtime_lane_id text not null,
  runtime_subdivision_id text,
  mapped_agent_capacity integer not null default 0,
  assignment_status text not null default 'mapped_readonly',
  assigned_by text,
  assigned_at timestamptz not null default now(),
  source text not null default 'mvp59_department_runtime_mapping',
  constraint runtime_department_lane_assignments_status_check check (assignment_status in ('mapped_readonly', 'readiness_review', 'eligible', 'blocked', 'disabled')), 
  constraint runtime_department_lane_assignments_department_unique unique (department_id)
);

create index if not exists runtime_department_lane_assignments_department_id_idx on runtime_department_lane_assignments (department_id);
create index if not exists runtime_department_lane_assignments_lane_id_idx on runtime_department_lane_assignments (runtime_lane_id);
create index if not exists runtime_department_lane_assignments_subdivision_id_idx on runtime_department_lane_assignments (runtime_subdivision_id);

create table if not exists runtime_department_readiness_notes (
  id uuid primary key default gen_random_uuid(),
  department_id text references runtime_departments(department_id) on delete cascade,
  note_type text not null default 'readiness_note',
  note_body text not null,
  actor text,
  created_at timestamptz not null default now(),
  source text not null default 'mvp59_department_runtime_mapping'
);

create index if not exists runtime_department_readiness_notes_department_id_idx on runtime_department_readiness_notes (department_id);
create index if not exists runtime_department_readiness_notes_created_at_idx on runtime_department_readiness_notes (created_at desc);

create table if not exists runtime_department_events (
  id uuid primary key default gen_random_uuid(),
  created_at timestamptz not null default now(),
  department_id text references runtime_departments(department_id) on delete cascade,
  actor text,
  event_type text not null,
  event_summary text not null,
  event_payload jsonb not null default '{}'::jsonb,
  source text not null default 'mvp59_department_runtime_mapping'
);

create index if not exists runtime_department_events_department_id_idx on runtime_department_events (department_id);
create index if not exists runtime_department_events_created_at_idx on runtime_department_events (created_at desc);

create table if not exists runtime_department_rollups (
  rollup_id uuid primary key default gen_random_uuid(),
  created_at timestamptz not null default now(),
  total_departments integer not null default 1777,
  mapped_departments integer not null default 0,
  readiness_review_departments integer not null default 0,
  eligible_departments integer not null default 0,
  blocked_departments integer not null default 0,
  disabled_departments integer not null default 0,
  total_registered_agents integer not null default 47979,
  live_runtime_agents_enabled integer not null default 0,
  full_47979_activation_blocked boolean not null default true,
  command_execution_enabled boolean not null default false,
  deploy_execution_enabled boolean not null default false,
  rollback_execution_enabled boolean not null default false,
  alert_sending_enabled boolean not null default false,
  source text not null default 'mvp59_department_runtime_mapping'
);

create index if not exists runtime_department_rollups_created_at_idx on runtime_department_rollups (created_at desc);

